auto_tag_order.script:
{% if event.preview %}
  {% assign order = hash %}
  {% assign order["admin_graphql_api_id"] = "gid://shopify/Order/1234567890" %}
  {% assign order["name"] = "#1001" %}
  {% comment %} Add more preview fields as needed {% endcomment %}
{% endif %}

{% assign tag_to_add = options.tag__required %}

{% if CONDITION_HERE %}
  {% unless options.test_mode__boolean %}
    {% action "shopify" %}
      mutation {
        tagsAdd(
          id: {{ order.admin_graphql_api_id | json }}
          tags: {{ tag_to_add | json }}
        ) {
          userErrors { field message }
        }
      }
    {% endaction %}
  {% else %}
    {% action "echo" order_name: order.name, tag: tag_to_add, action: "would tag order" %}
  {% endunless %}

  {% log message: "Tagged order", order: order.name, tag: tag_to_add %}
{% else %}
  {% log message: "Condition not met, skipping", order: order.name %}
{% endif %}

email_notification.script:
{% assign email_subject = options.email_subject__required %}
{% assign email_body = options.email_body__multiline_required %}

{% comment %} Replace placeholders {% endcomment %}
{% assign email_subject = email_subject | replace: "PLACEHOLDER", value %}
{% assign email_body = email_body | replace: "PLACEHOLDER", value %}

{% action "email" %}
  {
    "to": {{ recipient_email | json }},
    "subject": {{ email_subject | strip | json }},
    "body": {{ email_body | strip | newline_to_br | json }},
    "from_display_name": {{ shop.name | json }},
    "reply_to": {{ shop.customer_email | json }}
  }
{% endaction %}

bulk_operation.script:
{% if event.topic == "mechanic/user/trigger" %}
  {% capture bulk_operation_query %}
    query {
      products(query: "YOUR_QUERY") {
        edges {
          node {
            __typename
            id
            title
          }
        }
      }
    }
  {% endcapture %}

  {% action "shopify" %}
    mutation {
      bulkOperationRunQuery(
        query: {{ bulk_operation_query | json }}
      ) {
        bulkOperation { id status }
        userErrors { field message }
      }
    }
  {% endaction %}
{% elsif event.topic == "mechanic/shopify/bulk_operation" %}
  {% if event.preview %}
    {% capture bulkOperation_objects_jsonl %}
      {"__typename":"Product","id":"gid://shopify/Product/1234567890","title":"Sample Product"}
    {% endcapture %}
    {% assign bulkOperation = hash %}
    {% assign bulkOperation["objects"] = bulkOperation_objects_jsonl | parse_jsonl %}
  {% endif %}

  {% assign products = bulkOperation.objects | where: "__typename", "Product" %}

  {% for product in products %}
    {% comment %} Process each product {% endcomment %}
    {% log product: product.title %}
  {% endfor %}
{% endif %}

daily_reset_cache.script:
{% assign cache_key = "daily_count:" | append: task.id %}
{% assign count_today = cache[cache_key] | default: 0 %}

{% if event.topic == "shopify/orders/create" %}
  {% assign count_today = count_today | plus: 1 %}
  {% action "cache", "set", cache_key, count_today %}

  {% log daily_count: count_today %}

  {% if count_today >= options.maximum_daily_orders__number_required %}
    {% comment %} Send alert {% endcomment %}
  {% endif %}
{% elsif event.topic == "mechanic/scheduler/daily" %}
  {% action "cache", "del", cache_key %}
  {% log message: "Daily counter reset" %}
{% endif %}

status_report.script:
{% assign previous_midnight = "now" | date: "%Y-%m-%dT00:00:00%z" %}

{% if event.topic == "mechanic/user/trigger" or event.preview %}
  {% capture query %}
    query {
      orders(
        first: 250
        query: "created_at:>={{ previous_midnight | json }}"
      ) {
        nodes { id name totalPriceSet { shopMoney { amount } } }
      }
    }
  {% endcapture %}

  {% assign result = query | shopify %}
  {% assign orders = result.data.orders.nodes %}

  {% capture report_html %}
    <h2>Daily Status Report</h2>
    <p><strong>Orders today:</strong> {{ orders.size }}</p>
  {% endcapture %}

  {% action "email" %}
    {
      "to": {{ shop.email | json }},
      "subject": "Daily Report - {{ orders.size }} orders",
      "body": {{ report_html | json }}
    }
  {% endaction %}
{% endif %}

resource_picker.script:
{% comment %}
  Options:
  {{ options.product_to_monitor__picker_product__required }}
  {{ options.collections_to_sync__picker_collection_array }}
{% endcomment %}

{% assign product_id = options.product_to_monitor__picker_product__required %}

{% capture query %}
  query {
    product(id: {{ product_id | json }}) {
      id
      title
      variants(first: 250) {
        nodes { id sku inventoryQuantity }
      }
    }
  }
{% endcapture %}

{% assign result = query | shopify %}
{% assign product = result.data.product %}

{% log product_title: product.title, variant_count: product.variants.nodes.size %}

