pagination.code:
{% for n in (1..100) %}
  {% capture query %}
    query {
      resource(first: 250, after: {{ cursor | json }}) {
        pageInfo { hasNextPage endCursor }
        nodes { id }
      }
    }
  {% endcapture %}
  {% assign result = query | shopify %}
  {% if result.data.resource.pageInfo.hasNextPage == false %}
    {% break %}
  {% endif %}
  {% assign cursor = result.data.resource.pageInfo.endCursor %}
{% endfor %}

